715: // numFeasibleNodesToFind returns the number of feasible nodes that once found, the scheduler stops
716: // its search for more feasible nodes.
717: func (sched *Scheduler) numFeasibleNodesToFind(percentageOfNodesToScore *int32, numAllNodes int32) (numNodes int32) {
718: 	if numAllNodes < minFeasibleNodesToFind {
719: 		return numAllNodes
720: 	}
721: 
722: 	// Use profile percentageOfNodesToScore if it's set. Otherwise, use global percentageOfNodesToScore.
723: 	var percentage int32
724: 	if percentageOfNodesToScore != nil {
725: 		percentage = *percentageOfNodesToScore
726: 	} else {
727: 		percentage = sched.percentageOfNodesToScore
728: 	}
729: 
730: 	if percentage == 0 {
731: 		percentage = int32(50) - numAllNodes/125
732: 		if percentage < minFeasibleNodesPercentageToFind {
733: 			percentage = minFeasibleNodesPercentageToFind
734: 		}
735: 	}
736: 
737: 	numNodes = numAllNodes * percentage / 100
738: 	if numNodes < minFeasibleNodesToFind {
739: 		return minFeasibleNodesToFind
740: 	}
741: 
742: 	return numNodes
743: }
